diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..7380671c6923 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2899,6 +2899,79 @@ Instruction *InstCombinerImpl::foldICmpSubConstant(ICmpInst &Cmp,
 Instruction *InstCombinerImpl::foldICmpAddConstant(ICmpInst &Cmp,
                                                    BinaryOperator *Add,
                                                    const APInt &C) {
+  if (Cmp.getPredicate() == ICmpInst::ICMP_EQ) {
+    Value *X, *Y;
+    // icmp eq (add (zext i1 X), (zext i1 Y)), 1 --> xor i1 X, Y
+    // The sum of two boolean values equals 1 when exactly one is true (XOR).
+    if (C == 1 &&
+        match(Add->getOperand(0), m_ZExt(m_Value(X))) &&
+        match(Add->getOperand(1), m_ZExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) &&
+        Y->getType()->isIntOrIntVectorTy(1)) {
+      return BinaryOperator::CreateXor(X, Y);
+    }
+    // Handle commuted case
+    if (C == 1 &&
+        match(Add->getOperand(1), m_ZExt(m_Value(X))) &&
+        match(Add->getOperand(0), m_ZExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) &&
+        Y->getType()->isIntOrIntVectorTy(1)) {
+      return BinaryOperator::CreateXor(X, Y);
+    }
+    // icmp eq (add (zext i1 X), (zext i1 Y)), 2 --> and i1 X, Y
+    // The sum of two boolean values equals 2 when both are true (AND).
+    if (C == 2 &&
+        match(Add->getOperand(0), m_ZExt(m_Value(X))) &&
+        match(Add->getOperand(1), m_ZExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) &&
+        Y->getType()->isIntOrIntVectorTy(1)) {
+      return BinaryOperator::CreateAnd(X, Y);
+    }
+    // Handle commuted case
+    if (C == 2 &&
+        match(Add->getOperand(1), m_ZExt(m_Value(X))) &&
+        match(Add->getOperand(0), m_ZExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) &&
+        Y->getType()->isIntOrIntVectorTy(1)) {
+      return BinaryOperator::CreateAnd(X, Y);
+    }
+    // icmp eq (add (sext i1 X), (sext i1 Y)), -1 --> xor i1 X, Y
+    // sext of i1: 0 -> 0, 1 -> -1. Sum is -1 when exactly one is true.
+    if (C.isAllOnes() &&
+        match(Add->getOperand(0), m_SExt(m_Value(X))) &&
+        match(Add->getOperand(1), m_SExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) &&
+        Y->getType()->isIntOrIntVectorTy(1)) {
+      return BinaryOperator::CreateXor(X, Y);
+    }
+    // Handle commuted case
+    if (C.isAllOnes() &&
+        match(Add->getOperand(1), m_SExt(m_Value(X))) &&
+        match(Add->getOperand(0), m_SExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) &&
+        Y->getType()->isIntOrIntVectorTy(1)) {
+      return BinaryOperator::CreateXor(X, Y);
+    }
+    // icmp eq (add (sext i1 X), (sext i1 Y)), -2 --> and i1 X, Y
+    // sext of i1: 0 -> 0, 1 -> -1. Sum is -2 when both are true.
+    if (C.isMinSignedValue() &&
+        match(Add->getOperand(0), m_SExt(m_Value(X))) &&
+        match(Add->getOperand(1), m_SExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) &&
+        Y->getType()->isIntOrIntVectorTy(1)) {
+      return BinaryOperator::CreateAnd(X, Y);
+    }
+    // Handle commuted case
+    if (C.isMinSignedValue() &&
+        match(Add->getOperand(1), m_SExt(m_Value(X))) &&
+        match(Add->getOperand(0), m_SExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) &&
+        Y->getType()->isIntOrIntVectorTy(1)) {
+      return BinaryOperator::CreateAnd(X, Y);
+    }
+  }
+
+
   Value *Y = Add->getOperand(1);
   const APInt *C2;
   if (Cmp.isEquality() || !match(Y, m_APInt(C2)))

